class NoSellerNoBuyerOverride:
    """
    🔥 PRIORITY -20000: Jika down_energy == 0 → TIDAK ADA SELLER → LONG.
       Jika up_energy == 0 → TIDAK ADA BUYER → SHORT.
       Ini mengalahkan SEMUA sinyal lain karena market structure.
       
    🛡️ BAIT VACUUM TRAP DETECTION: Membedakan genuine vacuum vs HFT bait.
       - Jika BAIT phase + volume rendah + gerakan kecil + liq lebih dekat di sisi lawan → itu jebakan
       - Jika KILL phase atau gamma executing → genuine vacuum
    
    🛡️ KILL PHASE GUARD: Jangan paksa LONG/SHORT jika bertentangan dengan Greeks dan liquidity proximity.
       - Jika KILL phase + greeks_kill_direction jelas + liq lebih dekat mendukung Greeks + funding crowded → override NoSeller/NoBuyer
       
    🛡️ NEW: BLOCK NoSeller/NoBuyer jika OFI SHORT kuat + harga turun (IRYSUSDT pattern).
    """
    @staticmethod
    def detect(down_energy: float, up_energy: float,
               agg: float, change_5m: float,
               market_phase: str, volume_ratio: float,
               short_liq: float, long_liq: float,
               gamma_executing: bool,
               greeks_kill_direction: str = "",
               funding_rate: float = 0.0,
               # ===== NEW PARAMETERS =====
               ofi_bias: str = "NEUTRAL",
               ofi_strength: float = 0.0,
               rsi6: float = 50.0,
               rsi6_5m: float = 50.0,
               # ===== REAL VOLUME GATE (LECTURER SARAN LOGIC) =====
               latest_volume: float = 0,
               volume_ma10: float = 1,
               # ===== ARIAUSDT GUARD PARAMETERS (LECTURER SARAN) =====
               algo_type_bias: str = "NEUTRAL",   # ← BARU
               hft_6pct_bias: str = "NEUTRAL",    # ← BARU
               obv_trend: str = "NEUTRAL") -> dict:  # ← BARU
        
        # ========== ARIAUSDT GUARD: algo+hft both SHORT + OBV negatif = manufactured vacuum ==========
        # Jika algo DAN hft keduanya SHORT, dan OBV negatif, maka down_energy=0 adalah jebakan
        if down_energy < 0.01:
            # TAHAP 1.2: GUARD TAMBAHAN untuk BAIT phase
            if market_phase == "BAIT" and volume_ratio < 0.7:
                # Hanya izinkan jika ada konfirmasi exchange atau OBV
                short_liq_local = short_liq if short_liq is not None else 99.0
                long_liq_local = long_liq if long_liq is not None else 99.0
                if down_energy < 0.01 and short_liq_local < long_liq_local:
                    if result.get("exchange_safe_direction") != "LONG" and obv_trend not in ("POSITIVE_EXTREME", "POSITIVE"):
                        return {"override": False}
                genuine_short_squeeze = (short_liq < long_liq and short_liq < 2.0)
                if not genuine_short_squeeze:
                    return {"override": False}
            if (algo_type_bias == "SHORT" and 
                hft_6pct_bias == "SHORT" and
                obv_trend in ("NEGATIVE_EXTREME", "NEGATIVE")):
                return {"override": False}  # Jangan paksa LONG
        
        # ========== REAL VOLUME GATE (LECTURER SARAN LOGIC) ==========
        # Jika volume ultra kering (<15% MA10), down_energy = 0 bukan berarti "tidak ada seller"
        # melainkan "tidak ada siapapun yang trading" — HFT bisa gerakkan harga dengan biaya murah
        if volume_ma10 > 0 and down_energy < 0.01:
            real_ratio = latest_volume / volume_ma10
            if real_ratio < 0.15 and funding_rate > 0:
                # Volume terlalu kering untuk percaya no-seller signal
                return {"override": False}

        # ========== ENERGY > AGG GUARD (LECTURER SARAN LOGIC) ==========
        # Pada volume ultra rendah, order-book energy lebih reliable daripada agg.
        if volume_ratio < 0.5 and abs(up_energy - down_energy) > 5.0:
            energy_bias = "LONG" if up_energy > down_energy else "SHORT"
            agg_conflicts = (
                (energy_bias == "LONG" and agg < 0.4) or
                (energy_bias == "SHORT" and agg > 0.6)
            )
            if agg_conflicts:
                return {"override": False}
        
        # ========== GUARD: OFI SHORT kuat + harga turun = BLOCK LONG override ==========
        if down_energy < 0.01:
            if (ofi_bias == "SHORT" and ofi_strength > 0.7 and
                change_5m < 0 and
                (funding_rate < -0.0002 or market_phase == "BAIT")):
                # Jangan paksa LONG, biarkan sinyal OFI SHORT yang menentukan
                return {"override": False}
        
        # ========== GUARD: OFI LONG kuat + harga naik = BLOCK SHORT override ==========
        if up_energy < 0.01:
            if (ofi_bias == "LONG" and ofi_strength > 0.7 and
                change_5m > 0 and
                (funding_rate > 0.0002 or market_phase == "BAIT")):
                return {"override": False}
        
        # ========== GUARD: Jangan override jika Greeks kill direction bertentangan ==========
        # Kondisi: BAIT phase + volume rendah + funding positif (crowded long) + kill_direction SHORT
        # maka NO SELLER override ke LONG adalah jebakan. Kita block override.
        if down_energy < 0.01:
            if (market_phase == "BAIT" and
                volume_ratio < 0.7 and
                greeks_kill_direction == "SHORT" and
                funding_rate > 0.0003):
                # Jangan paksa LONG, biarkan Greeks atau detector lain yang menentukan
                return {"override": False}
        
        if up_energy < 0.01:
            if (market_phase == "BAIT" and
                volume_ratio < 0.7 and
                greeks_kill_direction == "LONG" and
                funding_rate < -0.0003):
                return {"override": False}
        
        # 🔥 LECTURER FIX: GUARD untuk exhausted squeeze - short liq sudah terlewati
        # Jika short_liq sudah tersapu dan kondisi overbought dengan volume rendah, jangan paksa LONG
        if down_energy < 0.01:
            if (short_liq < 2.0 and change_5m > short_liq * 1.2 and
                (rsi6 > 85 or rsi6_5m > 85) and volume_ratio < 0.6):
                return {"override": False}
        
        # KASUS down_energy == 0 (tidak ada seller)
        if down_energy < 0.01:
            # 🔥 GUARD: Jangan paksa LONG jika RSI overbought ekstrem + short_liq dekat
            if (rsi6 > 90 or rsi6_5m > 85) and short_liq < 2.0 and change_5m > 2.0:
                return {"override": False}
            
            # 🔥 GUARD DI KILL PHASE: Jangan paksa LONG jika Greeks bilang SHORT & long_liq lebih dekat & funding positif
            if (market_phase == "KILL" and
                greeks_kill_direction == "SHORT" and
                long_liq < short_liq and
                funding_rate > 0.0003):
                return {
                    "override": True,
                    "bias": "SHORT",
                    "reason": f"KILL PHASE GUARD: down_energy=0 tapi Greeks kill=SHORT, long_liq={long_liq:.2f}% < short_liq, funding={funding_rate:.5f} crowded long → forced SHORT (override NoSeller)",
                    "priority": -20001  # lebih tinggi dari NoSeller original
                }
            
            # 🔥 BAIT VACUUM TRAP (existing)
            if (market_phase == "BAIT" and 
                volume_ratio < 0.4 and 
                abs(change_5m) < 1.5 and 
                short_liq < long_liq):
                return {
                    "override": True,
                    "bias": "SHORT",
                    "reason": f"BAIT VACUUM TRAP: down_energy=0 tapi BAIT phase, vol={volume_ratio:.2f}x, move={change_5m:.1f}%, short_liq={short_liq:.2f}% < long_liq={long_liq:.2f}% → HFT bait, forced SHORT",
                    "priority": -20000
                }
            
            # Genuine vacuum (existing)
            return {
                "override": True,
                "bias": "LONG",
                "reason": f"NO SELLER (down_energy={down_energy:.3f}) → forced LONG",
                "priority": -20000
            }
        
        # KASUS up_energy == 0 (tidak ada buyer) - mirror guard
        if up_energy < 0.01:
            if (market_phase == "KILL" and
                greeks_kill_direction == "LONG" and
                short_liq < long_liq and
                funding_rate < -0.0003):
                return {
                    "override": True,
                    "bias": "LONG",
                    "reason": f"KILL PHASE GUARD: up_energy=0 tapi Greeks kill=LONG, short_liq={short_liq:.2f}% < long_liq, funding={funding_rate:.5f} crowded short → forced LONG (override NoBuyer)",
                    "priority": -20001
                }
            
            if (market_phase == "BAIT" and 
                volume_ratio < 0.4 and 
                abs(change_5m) < 1.5 and 
                long_liq < short_liq):
                return {
                    "override": True,
                    "bias": "LONG",
                    "reason": f"BAIT VACUUM TRAP: up_energy=0 tapi BAIT phase, vol={volume_ratio:.2f}x, move={change_5m:.1f}%, long_liq={long_liq:.2f}% < short_liq={short_liq:.2f}% → HFT bait, forced LONG",
                    "priority": -20000
                }
            
            return {
                "override": True,
                "bias": "SHORT",
                "reason": f"NO BUYER (up_energy={up_energy:.3f}) → forced SHORT",
                "priority": -20000
            }
        
        return {"override": False}


class LiquidityRegimeSwitcher:
    """
    🔥 LIQUIDITY REGIME SWITCHING - Priority -19950
    Membedakan regime:
    - DISTRIBUTION TRAP (SHORT): long_liq dekat + OBV negatif ekstrem + volume kering + funding positif
    - DIP THEN RIP (LONG): long_liq dekat + OBV tidak negatif + buy pressure
    - SHORT SQUEEZE (LONG): short_liq dekat + OBV tidak negatif + funding negatif
    """
    @staticmethod
    def detect(long_liq: float, short_liq: float,
               obv_trend: str, obv_value: float,
               agg: float, up_energy: float, down_energy: float,
               funding_rate: float, volume_ratio: float,
               rsi6: float, rsi6_5m: float,
               market_phase: str) -> dict:
        
        if funding_rate is None:
            funding_rate = 0.0
        
        # ===== REGIME 1: DISTRIBUTION TRAP (SHORT) =====
        if (long_liq < 2.0 and long_liq < short_liq and
            obv_trend in ("NEGATIVE_EXTREME", "NEGATIVE") and
            obv_value < -20_000_000 and
            volume_ratio < 0.6 and
            agg > 0.7 and
            funding_rate > 0.0003 and
            rsi6_5m < 60 and
            down_energy < 0.1):
            return {
                "override": True,
                "bias": "SHORT",
                "reason": f"REGIME: DISTRIBUTION TRAP. long_liq={long_liq:.2f}%, OBV={obv_trend}, volume kering, funding positif → HFT dump, SHORT",
                "priority": -19950
            }
        
        # ===== REGIME 2: DIP THEN RIP (LONG) =====
        if (long_liq < 2.0 and long_liq < short_liq and
            obv_trend not in ("NEGATIVE_EXTREME", "NEGATIVE") and
            agg > 0.7 and up_energy > 0.1 and down_energy < 0.01 and
            (funding_rate > 0.0002 or rsi6_5m > 40) and
            rsi6 > 10):  # threshold rendah untuk mencakup ONUSDT (RSI=12.6)
            return {
                "override": True,
                "bias": "LONG",
                "reason": f"REGIME: DIP THEN RIP. long_liq={long_liq:.2f}%, OBV tidak bearish, buy pressure → HFT sweep lalu pump, LONG",
                "priority": -19950
            }
        
        # ===== REGIME 3: SHORT SQUEEZE (LONG) =====
        if (short_liq < 2.0 and short_liq < long_liq and
            obv_trend not in ("NEGATIVE_EXTREME", "NEGATIVE") and
            agg > 0.7 and up_energy > 0.1 and
            funding_rate < -0.0003 and
            rsi6_5m < 75):
            return {
                "override": True,
                "bias": "LONG",
                "reason": f"REGIME: SHORT SQUEEZE. short_liq={short_liq:.2f}%, funding negatif, buy pressure → LONG",
                "priority": -19950
            }
        
        return {"override": False}


