class PhantomBuyEnergyTrap:
    """
    🔥 BSBUSDT PATTERN: up_energy besar tapi ask_slope jauh lebih besar
    
    HFT spoof up_energy dengan bid order besar di order book,
    tapi pasang ask wall jauh lebih besar di atas.
    
    Result: sistem lihat up_energy tinggi → pikir LONG kuat
    Kenyataan: ask wall akan menyerap semua buy → dump
    
    Deteksi: ask_slope > bid_slope * RATIO dan up_energy > 1.0
    tapi change_5m flat/negatif = energy tidak bisa tembus ask wall
    
    Priority: -1101 (di atas MasterSqueezeRule)
    """
    @staticmethod
    def detect(ask_slope: float, bid_slope: float,
               up_energy: float, down_energy: float,
               change_5m: float, volume_ratio: float,
               funding_rate: float,
               long_liq: float, short_liq: float) -> Dict:
        
        if bid_slope <= 0:
            return {"override": False}
        
        ask_bid_ratio = ask_slope / bid_slope
        
        # Ask wall ekstrem + up_energy ada tapi harga tidak naik = phantom
        if (ask_bid_ratio > 50.0 and          # ask wall 50x lebih tebal
            up_energy > 1.0 and               # ada "buy energy" (spoofed)
            down_energy < 0.1 and             # tidak ada seller nyata
            change_5m < 1.0 and              # harga tidak naik meski energy ada
            volume_ratio < 0.8):             # volume rendah = spoof mudah
            return {
                "override": True,
                "bias": "SHORT",
                "reason": (
                    f"PHANTOM BUY ENERGY TRAP: ask_slope={ask_slope:.0f} vs "
                    f"bid={bid_slope:.0f} (ratio {ask_bid_ratio:.0f}x), "
                    f"up_energy={up_energy:.2f} tapi harga cuma {change_5m:.1f}% "
                    f"→ buy energy palsu (spoof bid), ask wall raksasa akan dump"
                ),
                "priority": -1101
            }
        
        # Versi moderat: ratio > 20x + funding negatif (double trap)
        if (ask_bid_ratio > 20.0 and
            up_energy > 2.0 and
            change_5m < 0.5 and
            funding_rate is not None and
            funding_rate < -0.0001 and        # funding negatif = sistem pikir LONG
            volume_ratio < 0.8):
            return {
                "override": True,
                "bias": "SHORT",
                "reason": (
                    f"PHANTOM BUY ENERGY + FUNDING BAIT: ask/bid={ask_bid_ratio:.0f}x, "
                    f"funding={funding_rate:.5f} (crowded short bait), "
                    f"up_energy={up_energy:.2f} spoof → sistem dipancing LONG, "
                    f"kenyataannya ask wall dump"
                ),
                "priority": -1101
            }
        
        return {"override": False}


class DipThenRipSweep:
    """
    🔥 TRUUSDT PATTERN: long_liq sangat dekat = sweep victim, bukan dump target
    
    Ketika long_liq < 1.0% dan short_liq jauh (> 2x jarak long_liq):
    HFT strategy = Dip Then Rip:
    1. Turun sedikit (0.67%) untuk sweep long stop
    2. Setelah long stop habis, tidak ada yang jual lagi
    3. Pump ke short liq (3.06%) untuk squeeze short
    
    Sinyal konfirmasi:
    - agg > 0.6 (mayoritas buy = retail sudah positioning LONG)
    - up_energy > down_energy (buy pressure lebih kuat)
    - RSI oversold (sudah turun cukup = bouncing point)
    - bid_slope > ask_slope (buy wall lebih tebal = support di bawah)
    
    KUNCI: OBV NEGATIVE_EXTREME tidak relevan di sini karena
    sweep jangka pendek (< 1%) + pump jangka menengah > 3%
    
    Priority: -1103 (di atas funding ban)
    """
    @staticmethod
    def detect(long_liq: float, short_liq: float,
               agg: float, up_energy: float, down_energy: float,
               rsi6: float, bid_slope: float, ask_slope: float,
               volume_ratio: float, change_5m: float,
               obv_trend: str) -> Dict:
        
        # Core: long_liq sangat dekat tapi short_liq jauh lebih besar
        if long_liq <= 0:
            return {"override": False}
            
        liq_ratio = short_liq / long_liq  # TRUUSDT: 3.06/0.67 = 4.56x
        
        if (long_liq < 1.5 and              # long liq sangat dekat
            liq_ratio > 2.5 and             # short liq jauh lebih besar
            agg > 0.55 and                  # mayoritas buy
            up_energy > down_energy and     # buy pressure lebih kuat
            down_energy < 0.1 and           # hampir tidak ada seller
            rsi6 < 40):                     # oversold = bouncing point
            
            # Konfirmasi tambahan: bid wall lebih tebal
            bid_stronger = (bid_slope > 0 and 
                           ask_slope > 0 and 
                           bid_slope > ask_slope * 0.5)  # bid minimal 50% dari ask
            
            if bid_stronger or volume_ratio > 0.5:
                return {
                    "override": True,
                    "bias": "LONG",
                    "reason": (
                        f"DIP THEN RIP SWEEP: long_liq={long_liq:.2f}% dekat "
                        f"(sweep victim), short_liq={short_liq:.2f}% jauh "
                        f"(liq_ratio={liq_ratio:.1f}x), agg={agg:.2f} buy, "
                        f"rsi={rsi6:.1f} oversold, down_energy={down_energy:.2f} "
                        f"→ HFT dip {long_liq:.2f}% sweep long stop LALU pump "
                        f"ke short_liq {short_liq:.2f}%"
                    ),
                    "priority": -1103
                }
        
        # Mirror: short_liq sangat dekat = sweep then dump
        if short_liq > 0:
            liq_ratio_short = long_liq / short_liq
            if (short_liq < 1.5 and
                liq_ratio_short > 2.5 and
                agg < 0.45 and
                down_energy > up_energy and
                up_energy < 0.1 and
                rsi6 > 60):
                
                bid_weaker = (bid_slope > 0 and 
                             ask_slope > 0 and 
                             ask_slope > bid_slope * 0.5)
                
                if bid_weaker or volume_ratio > 0.5:
                    return {
                        "override": True,
                        "bias": "SHORT",
                        "reason": (
                            f"RIP THEN DIP SWEEP: short_liq={short_liq:.2f}% dekat "
                            f"(sweep victim), long_liq={long_liq:.2f}% jauh "
                            f"(ratio={liq_ratio_short:.1f}x) "
                            f"→ HFT pump sweep short stop LALU dump"
                        ),
                        "priority": -1103
                    }
        
        return {"override": False}


class SymmetricLiquidityBaitTrap:
    """
    🔥 PRIORITY -27480 (LEBIH TINGGI DARI TRUE SQUEEZE VALIDATOR -27450)
    
    Membatalkan sinyal squeeze ketika short_liq dan long_liq hampir sama,
    dan ada indikasi jebakan (Vega aktif, OFI berlawanan).
    """
    @staticmethod
    def detect(
        short_liq: float,
        long_liq: float,
        market_phase: str,
        vega_active: bool,
        ofi_bias: str,
        ofi_strength: float,
        agg: float,
        volume_ratio: float,
        current_bias: str  # bias yang akan dihasilkan oleh sistem (LONG/SHORT)
    ) -> dict:
        
        # 1. Selisih likuiditas sangat kecil
        if abs(short_liq - long_liq) >= 0.5:
            return {"override": False}
        
        # 2. Harus ada indikasi jebakan (BAIT phase atau Vega aktif)
        if not (market_phase == "BAIT" or vega_active):
            return {"override": False}
        
        # 3. Volume rendah (likuiditas tipis)
        if volume_ratio >= 1.0:
            return {"override": False}
        
        # 4. Cek apakah OFI atau agg bertentangan dengan bias squeeze
        #    (squeeze akan memaksa LONG jika short_liq < long_liq)
        squeeze_direction = "LONG" if short_liq < long_liq else "SHORT"
        
        # Jika sistem akan output LONG, tapi OFI SHORT kuat → jebakan
        if squeeze_direction == "LONG" and current_bias == "LONG":
            if ofi_bias == "SHORT" and ofi_strength > 0.7:
                return {
                    "override": True,
                    "bias": "NEUTRAL",
                    "reason": (
                        f"SYMMETRIC LIQUIDITY BAIT: short_liq={short_liq:.2f}% vs long_liq={long_liq:.2f}% "
                        f"(selisih {abs(short_liq-long_liq):.2f}%), BAIT phase, OFI SHORT {ofi_strength:.2f} → "
                        f"squeeze signal palsu, jangan LONG"
                    ),
                    "priority": -27480
                }
            if agg < 0.45 and ofi_bias == "SHORT":
                return {
                    "override": True,
                    "bias": "NEUTRAL",
                    "reason": (
                        f"SYMMETRIC LIQUIDITY BAIT: agg={agg:.2f} (sell dominant) + OFI SHORT → "
                        f"squeeze tidak valid, NO TRADE"
                    ),
                    "priority": -27480
                }
        
        # Mirror untuk SHORT
        if squeeze_direction == "SHORT" and current_bias == "SHORT":
            if ofi_bias == "LONG" and ofi_strength > 0.7:
                return {
                    "override": True,
                    "bias": "NEUTRAL",
                    "reason": (
                        f"SYMMETRIC LIQUIDITY BAIT: OFI LONG kuat, jangan SHORT"
                    ),
                    "priority": -27480
                }
            if agg > 0.55 and ofi_bias == "LONG":
                return {
                    "override": True,
                    "bias": "NEUTRAL",
                    "reason": (
                        f"SYMMETRIC LIQUIDITY BAIT: agg={agg:.2f} (buy dominant) + OFI LONG → "
                        f"dump signal tidak valid, NO TRADE"
                    ),
                    "priority": -27480
                }
        
        return {"override": False}


class AggSpoofDumpGuardValidator:
    """
    AggSpoofingActiveDumpGuard sering salah ketika:
    1. who_dies_first = BOTH_POSSIBLE (arah belum committed)
    2. up_energy tinggi (> 1.0) — ada buyer nyata
    3. rsi6_5m sangat rendah (< 20) — kapitulasi, bukan distribusi
    4. Data race: display_agg != json_agg gap > 0.20
    
    Jika salah satu kondisi ini ada, BLOCK AGG SPOOF DUMP
    dan kembalikan ke sinyal kapitulasi bounce.
    
    Priority: -27100 (lebih tinggi dari AGG SPOOF DUMP -10018.95)
    """
    @staticmethod
    def should_block_agg_spoof_dump(
        who_dies_first: str,
        up_energy: float,
        rsi6_5m: float,
        display_agg: float,
        json_agg: float,
        long_liq: float,
        short_liq: float,
        change_5m: float
    ) -> dict:
        
        reasons = []
        block = False
        
        # Kondisi 1: who_dies belum committed
        if who_dies_first == "BOTH_POSSIBLE":
            reasons.append(
                f"who_dies=BOTH_POSSIBLE (arah belum committed)"
            )
            block = True
        
        # Kondisi 2: up_energy tinggi = buyer nyata ada
        if up_energy > 1.5:
            reasons.append(
                f"up_energy={up_energy:.2f} > 1.5 (buyer nyata, bukan micro-injection)"
            )
            block = True
        
        # Kondisi 3: RSI5m kapitulasi absolut
        if rsi6_5m < 20:
            reasons.append(
                f"rsi6_5m={rsi6_5m:.1f} < 20 (kapitulasi absolut — bounce imminent)"
            )
            block = True
        
        # Kondisi 4: Data race detected
        if abs(display_agg - json_agg) > 0.20:
            reasons.append(
                f"data_race: display_agg={display_agg:.2f} vs json_agg={json_agg:.2f} "
                f"(gap={abs(display_agg-json_agg):.2f} > 0.20)"
            )
            block = True
        
        # Kondisi 5: long_liq jauh lebih dekat dari short_liq
        # = target bounce/sweep ada, bukan dump
        if long_liq < short_liq * 0.4 and change_5m < 0:
            reasons.append(
                f"long_liq={long_liq:.2f}% << short_liq={short_liq:.2f}% "
                f"(long dekat = akan di-sweep lalu bounce)"
            )
            block = True
        
        if block:
            return {
                "block": True,
                "suggested_bias": "LONG",
                "reason": (
                    f"AGG SPOOF DUMP BLOCKED: "
                    + " | ".join(reasons)
                    + f" → Kembalikan ke kapitulasi bounce signal."
                )
            }
        
        return {"block": False}


class CapitulationBounceAbsoluteOverride:
    """
    Kondisi PALING KUAT untuk LONG yang sering diabaikan sistem:
    
    RSI5m < 20 + long_liq dekat + up_energy tinggi + down_energy = 0
    = Kapitulasi absolut + buyer sudah masuk + target sweep ada
    
    Ini harus override HAMPIR SEMUA sinyal SHORT karena:
    - RSI5m < 20 terjadi sangat jarang (< 5% dari waktu)
    - Ketika terjadi, probability bounce > 85%
    - Binance SELALU sweep long_liq dulu sebelum keputusan arah
    
    EXCEPTION (jangan LONG):
    - OBV negatif ekstrem DAN real_volume_ratio > 0.8 (genuine distribution aktif)
    - funding_rate > 0.002 (crowded LONG sangat ekstrem)
    - delta_exposure > 0.95 (hampir semua posisi LONG = cascade imminent)
    
    Priority: -27050 (tepat di bawah UltraLowVolumeAggSpoofing -27000)
    """
    @staticmethod
    def detect(
        rsi6_5m: float,
        long_liq: float,
        short_liq: float,
        up_energy: float,
        down_energy: float,
        change_5m: float,
        funding_rate: float,
        delta_exposure: float,
        obv_trend: str,
        latest_volume: float,
        volume_ma10: float,
        who_dies_first: str,
        exchange_safe_direction: str
    ) -> dict:
        
        if funding_rate is None:
            funding_rate = 0.0
        
        # RSI5m harus kapitulasi
        if rsi6_5m >= 20:
            return {"override": False}
        
        # long_liq harus dekat (target sweep)
        if long_liq >= 3.0:
            return {"override": False}
        
        # long_liq lebih dekat dari short_liq
        if long_liq >= short_liq:
            return {"override": False}
        
        # Harus ada buyer (up_energy > 0)
        if up_energy <= 0.3:
            return {"override": False}
        
        # Tidak ada seller aktif
        if down_energy >= 0.5:
            return {"override": False}
        
        # Harga sedang turun (setup bounce)
        if change_5m >= 0:
            return {"override": False}
        
        # ===== EXCEPTIONS — jangan LONG =====
        
        # Exception 1: Funding ekstrem + delta exposure hampir sempurna
        if funding_rate > 0.002 and delta_exposure > 0.93:
            return {"override": False}
        
        # Exception 2: Volume genuinely tinggi + OBV negatif
        # (distribusi nyata, bukan lagging)
        if volume_ma10 > 0:
            real_ratio = latest_volume / volume_ma10
            genuine_distribution = (
                obv_trend == "NEGATIVE_EXTREME" and
                real_ratio > 0.8
            )
            if genuine_distribution:
                return {"override": False}
        
        # Exception 3: who_dies = LONG_TRADERS sudah confirmed
        # (bukan BOTH_POSSIBLE)
        if who_dies_first == "LONG_TRADERS" and funding_rate > 0.001:
            return {"override": False}
        
        # Hitung confidence score
        score = 0
        score_reasons = []
        
        if rsi6_5m < 15:
            score += 2
            score_reasons.append(f"RSI5m={rsi6_5m:.1f} (extreme capitulation)")
        else:
            score += 1
            score_reasons.append(f"RSI5m={rsi6_5m:.1f} (capitulation)")
        
        if long_liq < 1.5:
            score += 2
            score_reasons.append(f"long_liq={long_liq:.2f}% (ultra close)")
        else:
            score += 1
            score_reasons.append(f"long_liq={long_liq:.2f}% (close)")
        
        if up_energy > 2.0:
            score += 2
            score_reasons.append(f"up_energy={up_energy:.2f} (strong buyers)")
        elif up_energy > 1.0:
            score += 1
            score_reasons.append(f"up_energy={up_energy:.2f} (moderate buyers)")
        
        if exchange_safe_direction == "LONG":
            score += 1
            score_reasons.append("exchange_safe=LONG (exchange confirms)")
        
        if who_dies_first == "BOTH_POSSIBLE":
            score += 1
            score_reasons.append("who_dies=BOTH (not committed SHORT)")
        
        # Butuh score >= 4
        if score < 4:
            return {"override": False}
        
        return {
            "override": True,
            "bias": "LONG",
            "reason": (
                f"CAPITULATION BOUNCE ABSOLUTE: "
                f"RSI5m={rsi6_5m:.1f} (<20, extreme capitulation), "
                f"long_liq={long_liq:.2f}% (sweep target dekat), "
                f"up_energy={up_energy:.2f} (buyer aktif masuk), "
                f"down_energy={down_energy:.2f} (no sellers), "
                f"change={change_5m:.1f}% (setup bounce). "
                f"exchange_safe={exchange_safe_direction}. "
                f"Score {score}: {' | '.join(score_reasons)}. "
                f"Override AGG SPOOF DUMP dan sinyal SHORT lainnya. Force LONG."
            ),
            "priority": -27050
        }


class ExchangeSafeDirectionRespector:
    """
    exchange_safe_direction adalah output dari ExchangeRiskScore
    yang menghitung dari perspektif Binance survival.
    
    Ketika exchange_safe_direction = LONG tapi bias = SHORT,
    sistem sedang bertarung melawan Binance sendiri.
    
    Kondisi untuk respect exchange_safe_direction:
    - exchange_safe_direction tidak NEUTRAL
    - exchange_risk_score >= 4 (risiko signifikan)
    - Bias saat ini berlawanan
    - who_dies_first = BOTH_POSSIBLE (belum committed)
    - rsi6_5m ekstrem (< 20 atau > 85)
    
    Priority: -27080
    """
    @staticmethod
    def detect(
        exchange_safe_direction: str,
        exchange_risk_score: int,
        current_bias: str,
        who_dies_first: str,
        rsi6_5m: float,
        up_energy: float,
        down_energy: float,
        long_liq: float,
        short_liq: float
    ) -> dict:
        
        if exchange_safe_direction == "NEUTRAL":
            return {"override": False}
        
        if exchange_risk_score < 4:
            return {"override": False}
        
        # Bias harus berlawanan dengan exchange recommendation
        if current_bias == exchange_safe_direction:
            return {"override": False}
        
        if who_dies_first not in ("BOTH_POSSIBLE", "UNCLEAR", ""):
            return {"override": False}
        
        # RSI harus ekstrem
        rsi_extreme = rsi6_5m < 20 or rsi6_5m > 85
        if not rsi_extreme:
            return {"override": False}
        
        # Energy harus konsisten dengan exchange direction
        if exchange_safe_direction == "LONG":
            energy_ok = up_energy > down_energy and up_energy > 0.5
            liq_ok = long_liq < short_liq
        else:
            energy_ok = down_energy > up_energy and down_energy > 0.5
            liq_ok = short_liq < long_liq
        
        if not (energy_ok or liq_ok):
            return {"override": False}
        
        return {
            "override": True,
            "bias": exchange_safe_direction,
            "reason": (
                f"EXCHANGE SAFE DIRECTION RESPECTED: "
                f"exchange_safe={exchange_safe_direction} "
                f"(risk_score={exchange_risk_score}/10), "
                f"current_bias={current_bias} (berlawanan = berbahaya), "
                f"who_dies={who_dies_first} (belum committed), "
                f"rsi6_5m={rsi6_5m:.1f} (extreme). "
                f"Jangan bertarung melawan Binance's own risk engine."
            ),
            "priority": -27080
        }


class OBVLaggingCapitulationGuard:
    """
    OBV NEGATIVE_EXTREME sering digunakan untuk blokir bounce.
    Tapi ketika RSI5m < 20, OBV negatif itu hampir selalu LAGGING.
    
    Kenapa?
    - OBV dibangun dari volume historis (bisa berasal dari 1-2 jam lalu)
    - Ketika RSI5m < 20, harga sudah turun sangat jauh
    - Pada titik ini, seller sudah exhausted
    - OBV masih negatif karena mencerminkan sell-off yang SUDAH TERJADI
    - Bukan prediksi sell-off yang AKAN terjadi
    
    Rule: Jika RSI5m < 20 DAN up_energy > down_energy DAN long_liq dekat,
    OBV NEGATIVE_EXTREME tidak boleh blokir LONG signal.
    
    Priority: digunakan sebagai modifier, bukan standalone override
    """
    @staticmethod
    def is_obv_lagging_at_capitulation(
        rsi6_5m: float,
        up_energy: float,
        down_energy: float,
        long_liq: float,
        obv_trend: str,
        change_5m: float
    ) -> bool:
        """Returns True jika OBV negatif kemungkinan besar lagging."""
        
        if obv_trend not in ("NEGATIVE_EXTREME", "NEGATIVE"):
            return False
        
        # RSI5m harus kapitulasi
        if rsi6_5m >= 20:
            return False
        
        # Buyer harus lebih kuat dari seller
        if up_energy <= down_energy:
            return False
        
        # long_liq harus dekat (ada target bounce)
        if long_liq >= 3.0:
            return False
        
        # Harga harus turun (kapitulasi setup)
        if change_5m >= 0:
            return False
        
        return True


class AggSpoofingActiveDumpGuard:
    """
    AINUSDT PATTERN: agg=0.98 (98% buy trades) TAPI price turun -2.9%
    + OBV NEGATIVE_EXTREME + funding positif tinggi + Greeks gamma executing SHORT
    
    Ini adalah HFT "Agg Spoofing Dump" yang paling licik:
    1. HFT inject ribuan micro-buy trades → agg = 0.98
    2. Sistem mengira ada buyer kuat → output LONG (reversal)
    3. Tapi price tetap turun karena sell pressure lebih besar
    4. Setelah LONG retail masuk → HFT dump besar
    
    Kunci pembeda:
    - Genuine bounce: agg tinggi + price NAIK (atau minimal flat)
    - Agg spoof: agg tinggi + price TURUN = mustahil jika agg genuine
    
    Jika 98% trades adalah BUY genuine, harga PASTI naik.
    Jika harga turun meski agg=0.98, berarti sell orders jauh lebih besar
    dalam dollar value (HFT sell satu order besar vs ribuan micro-buy retail).
    
    Konfirmasi wajib:
    - Greeks gamma_executing = True (kill sudah dimulai)
    - funding positif (crowded LONG = korban tersedia)
    - OBV negatif (distribusi sudah panjang)
    - long_liq lebih dekat dari short_liq
    
    Priority: -10018.95 (lebih tinggi dari semua reversal detector)
    Bias: SHORT
    """
    @staticmethod
    def detect(agg: float, change_5m: float, funding_rate: float,
               obv_trend: str, obv_value: float,
               greeks_gamma_executing: bool, greeks_gamma_exec_score: int,
               greeks_kill_direction: str, greeks_who_dies_first: str,
               long_liq: float, short_liq: float,
               volume_ratio: float, up_energy: float,
               rsi6_5m: float,
               # NEW: Parameters for lecturer's guard logic
               exchange_safe_direction: str = "NEUTRAL",
               exchange_risk_score: int = 0,
               display_agg: float = None) -> dict:
        
        if funding_rate is None:
            return {"override": False}
        
        # ===== LECTURER'S GUARDS - TAMBAHKAN DI AWAL =====
        # Guard 1: who_dies belum committed = jangan force SHORT
        if greeks_who_dies_first == "BOTH_POSSIBLE":
            return {"override": False}
        
        # Guard 2: up_energy tinggi = buyer nyata, bukan micro-injection
        if up_energy > 1.5:
            return {"override": False}
        
        # Guard 3: RSI5m kapitulasi = bounce lebih mungkin dari dump
        if rsi6_5m < 20:
            return {"override": False}
        
        # Guard 4: exchange_safe = LONG = jangan SHORT
        if exchange_safe_direction == "LONG" and rsi6_5m < 25:
            return {"override": False}
        
        # Core contradiction: agg sangat tinggi tapi harga turun
        agg_price_contradiction = agg > 0.85 and change_5m < -1.5
        
        if not agg_price_contradiction:
            return {"override": False}
        
        # Konfirmasi 1: OBV harus negatif (distribusi nyata)
        obv_bearish = obv_trend in ("NEGATIVE_EXTREME", "NEGATIVE")
        
        if not obv_bearish:
            return {"override": False}
        
        # Konfirmasi 2: funding positif = crowded LONG = korban ada
        funding_crowded_long = funding_rate > 0.0003
        
        if not funding_crowded_long:
            return {"override": False}
        
        # Konfirmasi 3: Greeks sudah committed SHORT
        greeks_short = (
            greeks_kill_direction == "SHORT" and
            greeks_who_dies_first == "LONG_TRADERS"
        )
        
        # Konfirmasi 4: long_liq lebih dekat dari short_liq (target jelas)
        liq_target_valid = long_liq < short_liq * 3
        
        # Hitung score
        score = sum([
            obv_bearish,
            funding_crowded_long,
            greeks_short,
            liq_target_valid,
            greeks_gamma_executing,
            greeks_gamma_exec_score >= 3,
            volume_ratio < 0.6,
        ])
        
        if score < 4:
            return {"override": False}
        
        return {
            "override": True,
            "bias": "SHORT",
            "reason": (
                f"AGG SPOOFING ACTIVE DUMP: agg={agg:.2f} ({agg*100:.0f}% buy trades) "
                f"TAPI price turun {change_5m:.1f}% → IMPOSSIBLE jika agg genuine. "
                f"Ini HFT inject micro-buy untuk jebak reversal signal. "
                f"OBV={obv_trend} ({obv_value:,.0f}) distribusi panjang, "
                f"funding={funding_rate:.6f} (crowded LONG = korban siap), "
                f"Greeks kill=SHORT gamma_executing={greeks_gamma_executing} "
                f"(exec_score={greeks_gamma_exec_score}), "
                f"long_liq={long_liq:.2f}% target. "
                f"Score {score}/7. Force SHORT, blokir semua reversal."
            ),
            "priority": -10018.95
        }


class FundingHighGreeksShortAggBaitVeto:
    """
    AINUSDT PATTERN: agg=1.00 + OFI=LONG 1.00 TAPI
    funding positif tinggi + greeks_kill=SHORT + greeks_who_dies=LONG
    + OBV negatif + RSI5m overbought
    
    Ini adalah kondisi paling berbahaya:
    HFT inject 100% micro-buy trades untuk membuat AggOFIFullBullish trigger,
    tapi semua sinyal fundamental menunjuk SHORT.
    
    Kaidah: ketika funding > 0.0008 DAN greeks_who_dies = LONG_TRADERS,
    agg=1.00 adalah 100% manipulasi. Greeks sudah committed bahwa LONG
    yang akan mati. Tidak ada alasan untuk LONG.
    
    Pembeda dengan genuine squeeze:
    - Genuine: funding NEGATIF (crowded SHORT yang squeeze)
    - Bait: funding POSITIF (crowded LONG yang akan dump)
    
    Priority: -10016.5 (lebih tinggi dari AggOFIFullBullish -10016)
    Bias: SHORT
    """
    @staticmethod
    def detect(agg: float, ofi_bias: str, ofi_strength: float,
               funding_rate: float,
               greeks_kill_direction: str,
               greeks_who_dies_first: str,
               greeks_vega_active: bool,
               obv_trend: str, obv_value: float,
               rsi6_5m: float, stoch_j: float,
               volume_ratio: float, short_liq: float,
               long_liq: float, change_5m: float) -> dict:
        
        if funding_rate is None:
            return {"override": False}
        
        # 🔥 GUARD CAPITULATION: Jangan veto jika capitulation setup
        # Ini adalah kasus AKEUSDT - biarkan CapitulationLongLiqSweepOverride yang handle
        capitulation_setup = (
            long_liq < 3.0 and
            rsi6_5m < 15 and
            change_5m < -5.0 and
            obv_trend in ("POSITIVE_EXTREME", "POSITIVE")
        )
        if capitulation_setup:
            return {"override": False}
        
        # Funding harus tinggi positif (crowded LONG)
        if funding_rate < 0.0007:
            return {"override": False}
        
        # Greeks harus committed SHORT dengan LONG yang mati
        greeks_committed_short = (
            greeks_kill_direction == "SHORT" and
            greeks_who_dies_first == "LONG_TRADERS"
        )
        if not greeks_committed_short:
            return {"override": False}
        
        # agg atau OFI harus terlihat sangat bullish (ini yang membuat
        # AggOFIFullBullish atau detector lain terjebak)
        looks_bullish = agg > 0.60 or (ofi_bias == "LONG" and ofi_strength > 0.5)
        if not looks_bullish:
            return {"override": False}
        
        # Konfirmasi bahwa ini adalah bait (minimal 3 dari 5)
        confirmations = {
            "vega_bait": greeks_vega_active,
            "obv_not_positive": obv_trend not in ("POSITIVE_EXTREME", "POSITIVE"),
            "rsi5m_overbought": rsi6_5m > 70,
            "stoch_maximal": stoch_j > 90,
            "volume_ultra_dry": volume_ratio < 0.4,
        }
        
        conf_count = sum(confirmations.values())
        if conf_count < 3:
            return {"override": False}
        
        # long_liq harus lebih jauh (target dump ada di sana)
        # short_liq dekat hanya sebagai umpan
        liq_trap = long_liq > short_liq * 2
        
        return {
            "override": True,
            "bias": "SHORT",
            "reason": (
                f"FUNDING HIGH GREEKS SHORT AGG BAIT VETO: "
                f"funding={funding_rate:.6f} (crowded LONG {funding_rate*100:.4f}%/8h), "
                f"greeks_kill={greeks_kill_direction}, "
                f"who_dies={greeks_who_dies_first} → LONG akan mati. "
                f"agg={agg:.2f} + OFI={ofi_bias} {ofi_strength:.2f} adalah BAIT "
                f"(Vega={greeks_vega_active} konfirmasi fake move). "
                f"OBV={obv_trend} ({obv_value:,.0f}), "
                f"RSI5m={rsi6_5m:.1f} overbought, "
                f"Stoch J={stoch_j:.1f} maximal, "
                f"volume={volume_ratio:.2f}x kering. "
                f"short_liq={short_liq:.2f}% adalah UMPAN, "
                f"target sebenarnya long_liq={long_liq:.2f}%. "
                f"Confirmations={conf_count}/5. "
                f"Veto AggOFIFullBullish. Force SHORT."
            ),
            "priority": -10016.5
        }


