class AdversarialTimingPattern:
    _price_history: Dict[str, deque] = {}
    
    @classmethod
    def record_price(cls, symbol: str, price: float, timestamp: float):
        if symbol not in cls._price_history:
            cls._price_history[symbol] = deque(maxlen=300)
        cls._price_history[symbol].append((timestamp, price))
    
    @classmethod
    def detect(cls, symbol: str, current_price: float,
               change_5m: float, volume_ratio: float,
               rsi6: float, rsi6_5m: float,
               ofi_bias: str, agg: float) -> dict:
        history = cls._price_history.get(symbol, deque())
        if len(history) < 30:
            return {"pattern_detected": False}
        now = time.time()
        prices_5m = [(t, p) for t, p in history if now - t <= 300]
        if len(prices_5m) < 10:
            return {"pattern_detected": False}
        recent_high = max(p for _, p in prices_5m)
        recent_low = min(p for _, p in prices_5m)
        pump_from_low = (current_price - recent_low) / recent_low * 100
        dump_from_high = (recent_high - current_price) / recent_high * 100
        
        # Pump kecil sebelum dump besar
        if (pump_from_low > 1.5 and pump_from_low < 5.0 and
            rsi6 > 85 and rsi6_5m < 70 and volume_ratio < 0.6 and ofi_bias == "SHORT"):
            return {
                "pattern_detected": True, "pattern_type": "PUMP_BEFORE_DUMP",
                "override": True, "bias": "SHORT", "priority": -28300,
                "reason": f"ADVERSARIAL TIMING: pump {pump_from_low:.1f}% dengan divergence, volume kering → akan dump"
            }
        # Dump kecil sebelum pump besar
        if (dump_from_high > 0.5 and dump_from_high < 3.0 and
            rsi6 < 30 and rsi6_5m > 40 and volume_ratio < 0.6 and ofi_bias == "LONG"):
            return {
                "pattern_detected": True, "pattern_type": "DIP_BEFORE_RIP",
                "override": True, "bias": "LONG", "priority": -28300,
                "reason": f"ADVERSARIAL TIMING: dip {dump_from_high:.1f}% dengan divergence, akan pump"
            }
        return {"pattern_detected": False}


class LiquidityRegimeClassifier:
    @staticmethod
    def classify(change_5m: float, volume_ratio: float,
                 agg: float, ofi_bias: str, ofi_strength: float,
                 short_liq: float, long_liq: float,
                 rsi6: float, rsi6_5m: float,
                 down_energy: float, up_energy: float,
                 funding_rate: float,
                 latest_volume: float, volume_ma10: float) -> dict:
        real_vol_ratio = latest_volume / volume_ma10 if volume_ma10 > 0 else 1.0
        scores = {"ACCUMULATION": 0, "MANIPULATION": 0, "DISTRIBUTION": 0,
                  "LIQUIDATION_HUNT": 0, "SQUEEZE": 0, "RECOVERY": 0}
        # MANIPULATION
        if agg > 0.85 and change_5m < 0: scores["MANIPULATION"] += 3
        if agg < 0.2 and change_5m > 0: scores["MANIPULATION"] += 3
        if real_vol_ratio < 0.15 and (agg > 0.9 or agg < 0.1): scores["MANIPULATION"] += 3
        if (ofi_bias == "SHORT" and change_5m > 1.5) or (ofi_bias == "LONG" and change_5m < -1.5): scores["MANIPULATION"] += 2
        # LIQUIDATION_HUNT
        min_liq = min(short_liq, long_liq)
        if min_liq < 2.0: scores["LIQUIDATION_HUNT"] += 3
        if min_liq < 1.0: scores["LIQUIDATION_HUNT"] += 3
        if abs(change_5m) > 2.0 and volume_ratio > 0.7: scores["LIQUIDATION_HUNT"] += 2
        # SQUEEZE
        if change_5m > 3.0 and volume_ratio > 0.8 and (rsi6 > 70 or rsi6 < 30): scores["SQUEEZE"] += 4
        if down_energy < 0.01 and short_liq < 2.0 and change_5m > 0: scores["SQUEEZE"] += 3
        if up_energy < 0.01 and long_liq < 2.0 and change_5m < 0: scores["SQUEEZE"] += 3
        # DISTRIBUTION
        if change_5m < -1.0 and agg > 0.7 and volume_ratio < 0.7: scores["DISTRIBUTION"] += 3
        if funding_rate is not None and funding_rate > 0.0005 and ofi_bias == "SHORT": scores["DISTRIBUTION"] += 2
        # ACCUMULATION
        if abs(change_5m) < 0.5 and volume_ratio < 0.5 and 0.3 < agg < 0.7: scores["ACCUMULATION"] += 4
        # RECOVERY
        if (rsi6 < 10 or rsi6 > 90) and abs(change_5m) < 1.0 and down_energy < 0.1: scores["RECOVERY"] += 3
        
        dominant = max(scores, key=scores.get)
        max_score = scores[dominant]
        regime_risk = {"ACCUMULATION": "HIGH_RISK", "MANIPULATION": "SKIP", "DISTRIBUTION": "MEDIUM_RISK",
                       "LIQUIDATION_HUNT": "LOW_RISK", "SQUEEZE": "MEDIUM_RISK", "RECOVERY": "HIGH_RISK"}
        entry_rec = {"ACCUMULATION": "WAIT", "MANIPULATION": "SKIP - DO NOT TRADE",
                     "DISTRIBUTION": "SHORT with tight SL", "LIQUIDATION_HUNT": "Follow liquidity direction",
                     "SQUEEZE": "Follow momentum, exit at liq target", "RECOVERY": "Wait for confirmation"}
        return {
            "regime": dominant, "scores": scores, "confidence": max_score,
            "risk_level": regime_risk.get(dominant, "UNKNOWN"),
            "entry_recommendation": entry_rec.get(dominant, "NEUTRAL"),
            "skip_entry": dominant == "MANIPULATION",
            "reason": f"Regime={dominant} (score={max_score}), risk={regime_risk.get(dominant)}"
        }


# ====================== END OF LECTURER'S SARAN CLASSES ======================


class OBVLaggingAggContradictionResolver:
    """
    🔥 OBV NEGATIVE_EXTREME tapi agg=1.00 = OBV LAGGING/STALE
    
    OBV dihitung dari volume historis. Ketika:
    - OBV = NEGATIVE_EXTREME (dari periode sebelumnya)
    - Tapi agg = 1.00 RIGHT NOW (100% trades buy saat ini)
    
    Ini berarti OBV mencerminkan kondisi SEBELUM pump dimulai.
    Real-time signal (agg) lebih akurat dari OBV yang lagging.
    
    Rule: Jika agg > 0.85 dan OBV berlawanan → ABAIKAN OBV,
    percaya agg sebagai ground truth real-time.
    
    Output: Jika ada detector yang pakai OBV untuk SHORT
    saat agg=1.00, BLOCK detector tersebut.
    
    Priority: -10015.5
    """
    @staticmethod
    def should_trust_agg_over_obv(agg: float, ofi_strength: float,
                                   obv_trend: str, down_energy: float,
                                   change_5m: float) -> bool:
        """Returns True jika agg lebih reliable dari OBV"""
        
        # LECTURER FIX: tambahkan case untuk SHORT ekstrem
        # agg sangat tinggi + OFI konfirmasi = real-time bullish nyata
        # ATAU agg sangat rendah + OFI konfirmasi = real-time bearish nyata
        agg_reliable = (
            (agg > 0.85 and ofi_strength > 0.7) or   # sisi LONG sudah ada
            (agg < 0.25 and ofi_strength > 0.5)        # tambah: sisi SHORT ekstrem
        )
        
        # OBV berlawanan dengan agg
        obv_bearish = obv_trend in ("NEGATIVE_EXTREME", "NEGATIVE")
        obv_bullish = obv_trend in ("POSITIVE_EXTREME", "POSITIVE")
        
        # Tidak ada seller (konfirmasi agg bukan spoof)
        no_seller = down_energy < 0.01
        
        # Harga naik (konsisten dengan agg bullish)
        price_up = change_5m > 0
        price_down = change_5m < 0
        
        # Trust agg jika:
        # - LONG side: agg tinggi + OFI kuat + OBV bearish + no seller + price up
        # - SHORT side: agg rendah + OFI kuat + OBV bullish + price down
        long_side = (agg > 0.85 and ofi_strength > 0.7 and obv_bearish and no_seller and price_up)
        short_side = (agg < 0.25 and ofi_strength > 0.5 and obv_bullish and price_down)
        
        return long_side or short_side
    
    @staticmethod
    def detect(agg: float, ofi_bias: str, ofi_strength: float,
               obv_trend: str, down_energy: float,
               change_5m: float, short_liq: float,
               long_liq: float, up_energy: float,
               funding_rate: float, rsi6: float = 50.0) -> dict:
        
        if funding_rate is None:
            funding_rate = 0.0
        
        # 🔥 LECTURER FIX: Lower agg threshold to 0.65 when RSI < 12 (capitulation)
        # At capitulation levels even 65% buy pressure with zero sellers is definitive
        agg_threshold = 0.65 if rsi6 < 12 else 0.85
        
        # Case LONG: agg ekstrem tinggi + OBV negatif = OBV lagging
        should_trust_agg_long = (
            agg > agg_threshold and ofi_strength > 0.7 and 
            obv_trend in ("NEGATIVE_EXTREME", "NEGATIVE") and
            down_energy < 0.01 and change_5m > 0
        )
        
        if should_trust_agg_long and short_liq > 0.3:
            return {
                "override": True,
                "bias": "LONG",
                "reason": (
                    f"OBV LAGGING AGG CONTRADICTION (LONG): "
                    f"agg={agg:.2f} ({agg*100:.0f}% BUY real-time) TAPI "
                    f"OBV={obv_trend} → OBV lagging/stale, percaya agg. Force LONG."
                    + (f" [RSI={rsi6:.1f} < 12 capitulation: lowered agg threshold to 0.65]" if rsi6 < 12 else "")
                ),
                "priority": -10015.5
            }
        
        # Case SHORT: agg ekstrem rendah + OBV positif = OBV lagging
        should_trust_agg_short = (
            agg < 0.25 and ofi_strength > 0.5 and 
            obv_trend in ("POSITIVE_EXTREME", "POSITIVE") and
            change_5m < 0
        )
        
        if should_trust_agg_short and long_liq > 0.3:
            return {
                "override": True,
                "bias": "SHORT",
                "reason": (
                    f"OBV LAGGING AGG CONTRADICTION (SHORT): "
                    f"agg={agg:.2f} ({(1-agg)*100:.0f}% SELL real-time) TAPI "
                    f"OBV={obv_trend} → OBV lagging/stale, percaya agg. Force SHORT."
                ),
                "priority": -10015.5
            }
        
        return {"override": False}


class UltraCloseLongLiqCascadeGuard:
    """
    🔥 CKBUSDT PATTERN (PRIORITY -10015 - TERTINGGI ABSOLUT):
    Long liq < 0.3% = BUKAN target sweep = CASCADE DUMP TRIGGER.
    
    Ketika long_liq sangat dekat (<0.3%), harga hampir menyentuh
    titik likuidasi massal. HFT tidak perlu setup apapun —
    tinggal push kecil dan cascade terjadi sendiri.
    
    Bedain dengan sweep normal (long_liq 1-3%):
    - Normal sweep: HFT perlu gerakan signifikan untuk trigger
    - Ultra close (<0.3%): satu candle kecil sudah cukup cascade
    
    Ini OVERRIDE semua detector yang bilang LONG karena
    "long_liq dekat = akan di-sweep lalu pump."
    
    Kondisi TAMBAHAN yang harus terpenuhi:
    - RSI5m > 65 (5m masih elevated = trend turun belum selesai)
    - ATAU OFI display ≠ agg (data race = tidak bisa dipercaya)
    - ATAU short_liq >> long_liq (jauh lebih banyak long daripada short)
    
    Case: CKBUSDT - long_liq 0.06-0.24%, RSI5m 81.2, SHORT 7.3%
    
    Priority: -10015 (LEBIH TINGGI dari FakeShortLiqTrap -10014)
    Bias: SHORT
    """
    @staticmethod
    def detect(long_liq: float, short_liq: float,
               rsi6_5m: float, rsi6: float,
               funding_rate: float,
               volume_ratio: float,
               change_5m: float) -> dict:
        
        # Core: long liq ULTRA dekat
        if long_liq >= 0.3:
            return {"override": False}
        
        # Long liq ultra dekat = cascade imminent
        # Konfirmasi dengan minimal 2 dari 4:
        
        # 1. RSI5m masih tinggi (trend 5m belum reversal)
        rsi5m_elevated = rsi6_5m > 65
        
        # 2. Short liq jauh lebih besar (tidak ada short yang perlu di-squeeze)
        liq_asymmetric = short_liq > long_liq * 5
        
        # 3. Volume kering (tidak ada rescue buyer)
        volume_dry = volume_ratio < 0.6
        
        # 4. Funding tidak crowded short
        not_crowded_short = funding_rate > -0.002
        
        score = sum([rsi5m_elevated, liq_asymmetric, volume_dry, not_crowded_short])
        
        if score >= 2:
            return {
                "override": True,
                "bias": "SHORT",
                "reason": (
                    f"ULTRA CLOSE LONG LIQ CASCADE: "
                    f"long_liq={long_liq:.2f}% (<0.3% = cascade threshold), "
                    f"short_liq={short_liq:.2f}% (ratio {short_liq/long_liq:.0f}x), "
                    f"RSI5m={rsi6_5m:.1f}, volume={volume_ratio:.2f}x, "
                    f"funding={funding_rate:.6f} → "
                    f"BUKAN sweep target. Ini CASCADE DUMP trigger. "
                    f"Satu push kecil = liquidasi massal LONG. "
                    f"Score: {score}/4"
                ),
                "priority": -10015
            }
        
        return {"override": False}


class RealSellerCascadeGuard:
    """
    🔥 LECTURER FIX 2 - REAL SELLER CASCADE GUARD (PRIORITY -10015.5):
    
    long_liq sangat dekat (<0.5%) + down_energy tinggi (>1.0) + agg rendah (<0.5)
    = HFT akan DRIVE THROUGH long liq (cascade), bukan bounce.
    
    Berbeda dari UltraCloseLongLiqCascadeGuard yang cek RSI5m.
    Ini fokus pada energy + agg sebagai bukti seller aktif.
    
    Kondisi yang harus terpenuhi (minimal 3 dari 4):
    - long_liq < 0.5% (ultra close cascade target)
    - down_energy > 1.0 (real sellers present)
    - agg < 0.5 (sell dominant trades)
    - change_5m < 0 (price falling)
    - hft_bias == "SHORT" or algo_bias == "SHORT" (HFT/Algo konfirmasi)
    
    Priority -10015.5 (antara UltraCascade -10015 dan FakeShortLiq -10014)
    Bias: SHORT
    
    Case: RAVEUSDT - long_liq 0.33%, down_energy 5.93, agg 0.41 = CASCADE BUKAN BOUNCE
    """
    @staticmethod
    def detect(long_liq: float, short_liq: float, down_energy: float,
               agg: float, change_5m: float, hft_bias: str, algo_bias: str) -> dict:
        
        if long_liq >= 0.5:
            return {"override": False}
        
        # Sellers aktif + harga turun + HFT/Algo konfirmasi = cascade
        real_seller = down_energy > 1.0
        sell_dominant = agg < 0.5
        price_falling = change_5m < 0
        hft_algo_short = (hft_bias == "SHORT" or algo_bias == "SHORT")
        
        score = sum([real_seller, sell_dominant, price_falling, hft_algo_short])
        
        if score >= 3:
            return {
                "override": True,
                "bias": "SHORT",
                "reason": (
                    f"REAL SELLER CASCADE: long_liq={long_liq:.2f}% ultra close, "
                    f"down_energy={down_energy:.2f} (real sellers), "
                    f"agg={agg:.2f} (sell dominant), "
                    f"change={change_5m:.1f}% → "
                    f"HFT akan DRIVE THROUGH long liq bukan bounce. "
                    f"Score: {score}/4"
                ),
                "priority": -10015.5
            }
        
        return {"override": False}


class RSIDivergenceExtremeWithLiqContext:
    """
    🔥 CKBUSDT PATTERN (PRIORITY -10014.5):
    RSI1m sangat oversold + RSI5m sangat overbought + long_liq dekat
    = Trend 5m mendominasi, bounce 1m adalah jebakan.
    
    Sistem sudah ada RSIDivergenceHighMomentumTrap tapi kalah
    dari detector lain. Ini versi yang lebih kuat dengan konteks likuiditas.
    
    Logic:
    - RSI1m < 35: harga baru turun di 1m (orang mau beli)
    - RSI5m > 70: trend 5m masih turun dari overbought
    - Gap > 35 poin: divergence sangat ekstrem
    - long_liq dekat: ada gravitasi ke bawah
    - Volume rendah: bounce tidak ada fuel
    
    Case: CKBUSDT - RSI1m 32.4, RSI5m 81.2, gap 48.8 poin
    
    Priority: -10014.5 (di bawah UltraCascade -10015, di atas FakeShortLiq -10014)
    Bias: SHORT
    """
    @staticmethod
    def detect(rsi6: float, rsi6_5m: float,
               long_liq: float, short_liq: float,
               volume_ratio: float,
               change_5m: float,
               funding_rate: float) -> dict:
        
        if funding_rate is None:
            funding_rate = 0.0
        
        rsi_gap = rsi6_5m - rsi6  # positif = 5m lebih tinggi dari 1m
        
        # Divergence ekstrem: 1m oversold tapi 5m masih tinggi
        extreme_divergence = (
            rsi6 < 35 and
            rsi6_5m > 70 and
            rsi_gap > 35
        )
        
        if not extreme_divergence:
            return {"override": False}
        
        # Konteks likuiditas: long_liq lebih dekat
        long_liq_closer = long_liq < short_liq
        
        # Volume kering (bounce tidak ada momentum)
        volume_dry = volume_ratio < 0.6
        
        # Funding tidak crowded short (tidak ada squeeze setup)
        not_crowded_short = funding_rate > -0.001
        
        # Harga turun atau flat (bukan sedang pumping)
        price_weak = change_5m < 0.5
        
        score = sum([long_liq_closer, volume_dry, not_crowded_short, price_weak])
        
        if score >= 3:
            return {
                "override": True,
                "bias": "SHORT",
                "reason": (
                    f"RSI DIVERGENCE EXTREME WITH LIQ CONTEXT: "
                    f"RSI1m={rsi6:.1f} (oversold) vs RSI5m={rsi6_5m:.1f} "
                    f"(gap={rsi_gap:.0f} poin), "
                    f"long_liq={long_liq:.2f}% closer, "
                    f"volume={volume_ratio:.2f}x, "
                    f"funding={funding_rate:.6f} → "
                    f"Trend 5m mendominasi. "
                    f"Bounce 1m adalah jebakan. "
                    f"Score: {score}/4"
                ),
                "priority": -10014.5
            }
        
        return {"override": False}


