        self.hawkes_R = 0.0            # recursive sum e^(-beta*(t-t_i))
        self.hawkes_last_t = time.time()
        self.hawkes_intensity = self.hawkes_mu
        self.hawkes_branching = 0.0
        
        # Tambahkan storage untuk trade timestamps
